/* ==============================================================================
 * 测试夹具：MrtkMailBoxTest
 * ============================================================================== */

/**
 * @class MrtkMailBoxTest
 * @brief 邮箱模块测试夹具
 * @details 提供 Mock 环境、系统初始化和辅助方法
 */
class MrtkMailBoxTest : public ::testing::Test {
  protected:
    /* Mock 对象（使用 NiceMock 自动忽略未设置期望的调用，避免 GMOCK WARNING） */
    testing::NiceMock<MockCpuPort> mock_cpu_port;

    /* 测试用邮箱对象 */
    mrtk_mb_t test_mb_static;
    mrtk_mb_t *test_mb_dynamic = nullptr;

    /* 测试用邮箱池（静态分配） */
    static constexpr mrtk_u32_t MAILBOX_SIZE = 256; /* 字节 */
    mrtk_u32_t mb_pool_buffer[64]; /* 256 字节，足够存储 64 个 mrtk_u32_t */
    mrtk_u32_t mb_pool_small[4];   /* 小邮箱池，用于边界测试 */

    /* 测试用任务对象 */
    static constexpr mrtk_u32_t TASK_STACK_SIZE = 512;
    mrtk_u32_t task_stack_high[512];
    mrtk_u32_t task_stack_mid[512];
    mrtk_u32_t task_stack_low[512];
    mrtk_task_t task_high;
    mrtk_task_t task_mid;
    mrtk_task_t task_low;

    /* 优先级定义 */
    static constexpr mrtk_u8_t PRIO_HIGH = 5;
    static constexpr mrtk_u8_t PRIO_MID  = 10;
    static constexpr mrtk_u8_t PRIO_LOW  = 20;

    /* 任务入口函数（空实现，仅用于测试） */
    static mrtk_void_t dummy_task_entry(mrtk_void_t *param) {
        (void)param;
        /* 测试任务不会实际运行，仅验证状态管理 */
    }

  protected:
    /**
     * @brief 测试环境初始化
     * @details 执行顺序：系统初始化 → 设置 Mock → 设置默认行为 → 初始化测试对象
     */
    void SetUp() override {
        /* Step 1: 系统初始化（复位全局变量） */
        mrtk_system_init();

        g_CurrentTCB = mrtk_task_get_idle();

        /* Step 2: 设置 Mock 对象 */
        mrtk_mock_set_cpu_port(&mock_cpu_port);

        /* Step 3: 设置默认期望行为（避免对中断控制产生不必要依赖） */
        ON_CALL(mock_cpu_port, mrtk_hw_interrupt_disable)
            .WillByDefault(testing::Return(0));
        ON_CALL(mock_cpu_port, mrtk_hw_interrupt_enable)
            .WillByDefault(testing::Return());
        ON_CALL(mock_cpu_port, mrtk_hw_context_switch_interrupt)
            .WillByDefault(testing::Return());

        /* Step 4: 初始化测试任务 */
        init_test_tasks();
    }

    /**
     * @brief 测试环境清理
     * @details 清除 Mock 对象，释放动态分配的资源
     */
    void TearDown() override {
        /* 释放动态创建的邮箱 */
        if (test_mb_dynamic != nullptr) {
            mrtk_free(test_mb_dynamic);
            test_mb_dynamic = nullptr;
        }

        /* 清除 Mock 对象 */
        mrtk_mock_clear_cpu_port();
    }

    /**
     * @brief 初始化测试用任务
     * @details 创建高/中/低三个优先级的任务，用于测试多任务场景
     */
    void init_test_tasks(mrtk_void_t) {
        mrtk_task_init("TaskHigh", &task_high, dummy_task_entry, nullptr,
                       task_stack_high, TASK_STACK_SIZE, PRIO_HIGH, 10);
        mrtk_task_init("TaskMid", &task_mid, dummy_task_entry, nullptr,
                       task_stack_mid, TASK_STACK_SIZE, PRIO_MID, 10);
        mrtk_task_init("TaskLow", &task_low, dummy_task_entry, nullptr,
                       task_stack_low, TASK_STACK_SIZE, PRIO_LOW, 10);
    }

    /**
     * @brief 设置当前运行任务
     * @details 模拟指定任务正在运行，用于测试邮箱操作
     * @param[in] task 要设置为当前运行的任务指针
     */
    void set_current_task(mrtk_task_t *task) {
        extern mrtk_tcb_t *volatile g_CurrentTCB;
        g_CurrentTCB = task;
    }

    /**
     * @brief 验证邮箱状态
     * @details 断言邮箱的关键字段是否符合预期
     * @param[in] mb          邮箱指针
     * @param[in] cur_cnt     期望的当前邮件数量
     * @param[in] in_offset   期望的写入偏移量
     * @param[in] out_offset  期望的读取偏移量
     */
    void verify_mb_state(mrtk_mb_t *mb, mrtk_u16_t cur_cnt, mrtk_u16_t in_offset,
                         mrtk_u16_t out_offset) {
        EXPECT_EQ(mb->cur_mail_cnt, cur_cnt);
        EXPECT_EQ(mb->in_offset, in_offset);
        EXPECT_EQ(mb->out_offset, out_offset);
    }

    /**
     * @brief 设置任务为就绪状态
     * @details 将任务插入对应优先级的就绪队列
     * @param[in] task 要设置为就绪的任务
     */
    void make_task_ready(mrtk_task_t *task) {
        task->state = MRTK_TASK_STAT_READY;
        _mrtk_schedule_insert_task(task);
    }

    /**
     * @brief 设置任务为挂起状态
     * @details 将任务从就绪队列移除并标记为挂起
     * @param[in] task 要设置为挂起的任务
     */
    void make_task_suspend(mrtk_task_t *task) {
        _mrtk_schedule_remove_task(task);
        task->state = MRTK_TASK_STAT_SUSPEND;
    }
};

