/**
 * @test MB_Init_ValidParameters_Success
 * @brief 测试正常初始化邮箱
 * @details 验证邮箱初始化后所有字段是否正确设置
 * @Given 有效的邮箱指针、邮箱池和参数
 * @When 调用 mrtk_mb_init()
 * @Then 返回 MRTK_EOK，邮箱状态正确
 */
TEST_F(MrtkMailBoxTest, MB_Init_ValidParameters_Success) {
    // Step 1: Given - 准备有效的邮箱对象和参数
    const mrtk_char_t *mb_name = "TestMB";
    mrtk_u8_t flag = MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO;

    // Step 2: When - 执行初始化
    mrtk_err_t ret = mrtk_mb_init(&test_mb_static, mb_pool_buffer, MAILBOX_SIZE, (mrtk_char_t *)mb_name, flag);

    // Step 3: Then - 验证返回值和邮箱状态
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(test_mb_static.msg_pool, mb_pool_buffer);
    EXPECT_GT(test_mb_static.max_mail_cnt, 0);
    verify_mb_state(&test_mb_static, 0, 0, 0);
}

