/**
 * @test MB_Detach_WithWaitingSenders_SendersResumedWithError
 * @brief 测试脱离时有等待发送者的邮箱
 * @details 验证脱离时唤醒所有等待发送者并设置错误码
 * @Given 邮箱已满，有任务在等待发送队列中
 * @When 调用 mrtk_mb_detach()
 * @Then 所有等待发送者被唤醒，last_error 设置为 MRTK_EDELETED
 */
TEST_F(MrtkMailBoxTest, MB_Detach_WithWaitingSenders_SendersResumedWithError) {
    // Step 1: Given - 初始化邮箱并有任务等待发送
    mrtk_mb_init(&test_mb_static, mb_pool_small, sizeof(mrtk_u32_t), "TestMB",
                 MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // 填满邮箱
    mrtk_u32_t mail = 0x12345678;
    mrtk_mb_send_wait(&test_mb_static, &mail, 0);
    ASSERT_EQ(test_mb_static.cur_mail_cnt, 1);

    // 将高优先级任务挂起到发送者等待队列
    set_current_task(&task_high);
    make_task_suspend(&task_high);
    task_high.last_error = MRTK_EOK;
    _mrtk_list_insert_before(&test_mb_static.suspend_sender, &task_high.sched_node);

    // Step 2: When - 脱离邮箱
    mrtk_err_t ret = mrtk_mb_detach(&test_mb_static);

    // Step 3: Then - 验证返回值和任务状态
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(task_high.last_error, MRTK_EDELETED);
}

