/**
 * @test MB_RoundTrip_FillAndDrain_VerifyOffsets
 * @brief 测试环形缓冲区填满和排空过程中的偏移量变化
 * @details 验证 in_offset 和 out_offset 在 0/1 之间正确切换（模拟环形特性）
 * @Given 邮箱容量为 2
 * @When 填满邮箱→排空邮箱→再次发送接收
 * @Then 偏移量正确切换，数据 FIFO 顺序正确
 */
TEST_F(MrtkMailBoxTest, MB_RoundTrip_FillAndDrain_VerifyOffsets) {
    // Step 1: Given - 初始化邮箱（容量为 2）
    mrtk_u32_t small_pool[2];
    mrtk_mb_init(&test_mb_static, small_pool, sizeof(small_pool), "TestMB",
                 MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);

    // Step 2: When - 填满邮箱（验证 in_offset 在 0/1 间切换）
    mrtk_u32_t mail1 = 0x11111111;
    mrtk_u32_t mail2 = 0x22222222;
    mrtk_mb_send_wait(&test_mb_static, &mail1, 0);
    ASSERT_EQ(test_mb_static.in_offset, 1);  /* 验证 in_offset: 0→1 */
    ASSERT_EQ(test_mb_static.cur_mail_cnt, 1);

    mrtk_mb_send_wait(&test_mb_static, &mail2, 0);
    ASSERT_EQ(test_mb_static.in_offset, 0);  /* 验证 in_offset: 1→0 (模拟回绕) */
    ASSERT_EQ(test_mb_static.cur_mail_cnt, 2);  /* 邮箱已满 */

    // Step 3: Then - 排空邮箱（验证 out_offset 在 0/1 间切换，数据 FIFO 顺序）
    mrtk_u32_t recv_mail;
    mrtk_mb_recv(&test_mb_static, &recv_mail, 0);
    ASSERT_EQ(recv_mail, mail1);  /* FIFO: 先进先出 */
    ASSERT_EQ(test_mb_static.out_offset, 1);  /* 验证 out_offset: 0→1 */
    ASSERT_EQ(test_mb_static.cur_mail_cnt, 1);

    mrtk_mb_recv(&test_mb_static, &recv_mail, 0);
    ASSERT_EQ(recv_mail, mail2);  /* FIFO: 后进后出 */
    ASSERT_EQ(test_mb_static.out_offset, 0);  /* 验证 out_offset: 1→0 (模拟回绕) */
    ASSERT_EQ(test_mb_static.cur_mail_cnt, 0);  /* 邮箱已空 */

    // Step 4: When - 再次发送和接收（验证邮箱可重复使用）
    mrtk_u32_t mail3 = 0x33333333;
    mrtk_mb_send_wait(&test_mb_static, &mail3, 0);
    ASSERT_EQ(test_mb_static.in_offset, 1);  /* 验证 in_offset: 0→1 */
    ASSERT_EQ(test_mb_static.cur_mail_cnt, 1);

    mrtk_mb_recv(&test_mb_static, &recv_mail, 0);
    ASSERT_EQ(recv_mail, mail3);
    ASSERT_EQ(test_mb_static.out_offset, 1);  /* 验证 out_offset: 0→1 */
    ASSERT_EQ(test_mb_static.cur_mail_cnt, 0);
}

