/**
 * @test MB_CompleteLifecycle_InitSendRecvDetach_Success
 * @brief 测试邮箱完整生命周期
 * @details 验证 Init → Send → Recv → Detach 的完整流程
 * @Given 邮箱对象
 * @When 依次执行 init, send, recv, detach
 * @Then 每一步都成功返回
 */
TEST_F(MrtkMailBoxTest, MB_CompleteLifecycle_InitSendRecvDetach_Success) {
    // Step 1: Given - 邮箱对象和任务

    // Step 2: When - 执行完整生命周期
    mrtk_err_t ret_init = mrtk_mb_init(&test_mb_static, mb_pool_buffer, MAILBOX_SIZE, "LifecycleMB",
                                         MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    set_current_task(&task_high);
    make_task_ready(&task_high);

    mrtk_u32_t sent_mail = 0x99887766;
    mrtk_err_t ret_send = mrtk_mb_send_wait(&test_mb_static, &sent_mail, 100);

    mrtk_u32_t recv_mail;
    mrtk_err_t ret_recv = mrtk_mb_recv(&test_mb_static, &recv_mail, 100);

    mrtk_err_t ret_detach = mrtk_mb_detach(&test_mb_static);

    // Step 3: Then - 验证每一步都成功
    EXPECT_EQ(ret_init, MRTK_EOK);
    EXPECT_EQ(ret_send, MRTK_EOK);
    EXPECT_EQ(ret_recv, MRTK_EOK);
    EXPECT_EQ(recv_mail, sent_mail);
    EXPECT_EQ(ret_detach, MRTK_EOK);
}

/**
 * @test MB_ProducerConsumer_MultipleTasks
 * @brief 测试生产者-消费者模式
 * @details 验证多任务发送和接收的正确性
 * @Given 多个任务向同一邮箱发送和接收邮件
 * @When 各任务进行 send/recv 操作
 * @Then 邮件正确传递，无数据损坏
 */
TEST_F(MrtkMailBoxTest, MB_ProducerConsumer_MultipleTasks) {
    // Step 1: Given - 初始化邮箱
    mrtk_u32_t pool[8]; /* 容量为 8 */
    mrtk_mb_init(&test_mb_static, pool, sizeof(pool), "PCMB",
                 MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // Step 2: When - 高优先级任务发送 3 封邮件
    set_current_task(&task_high);
    make_task_ready(&task_high);

    for (mrtk_u32_t i = 0; i < 3; ++i) {
        mrtk_u32_t mail = 0x10000000 | i;
        mrtk_err_t ret = mrtk_mb_send_wait(&test_mb_static, &mail, 0);
        ASSERT_EQ(ret, MRTK_EOK);
    }

    // Step 3: Then - 中优先级任务接收 3 封邮件并验证
    set_current_task(&task_mid);
    make_task_ready(&task_mid);

    for (mrtk_u32_t i = 0; i < 3; ++i) {
        mrtk_u32_t recv_mail;
        mrtk_err_t ret = mrtk_mb_recv(&test_mb_static, &recv_mail, 0);
        EXPECT_EQ(ret, MRTK_EOK);
        EXPECT_EQ(recv_mail, (0x10000000 | i));
    }

    EXPECT_EQ(test_mb_static.cur_mail_cnt, 0);
}

