/**
 * @test MB_RoundTrip_CompleteCycle
 * @brief 测试完整的发送-接收循环
 * @details 验证环形缓冲区的完整读写循环
 * @Given 邮箱容量为 N
 * @When 发送 N 封邮件，然后接收 N 封邮件
 * @Then 偏移量正确回绕，数据完整
 */
TEST_F(MrtkMailBoxTest, MB_RoundTrip_CompleteCycle) {
    // Step 1: Given - 初始化邮箱（容量为 4）
    mrtk_u32_t pool[4];
    mrtk_mb_init(&test_mb_static, pool, sizeof(pool), "TestMB",
                 MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);

    // Step 2: When - 发送 4 封邮件填满邮箱
    for (mrtk_u32_t i = 0; i < 4; ++i) {
        mrtk_u32_t mail = 0xAABBCC00 | i;
        mrtk_err_t ret = mrtk_mb_send_wait(&test_mb_static, &mail, 0);
        ASSERT_EQ(ret, MRTK_EOK);
    }
    ASSERT_EQ(test_mb_static.cur_mail_cnt, 4);
    ASSERT_EQ(test_mb_static.in_offset, 0); /* 回绕到 0 */

    // Step 3: Then - 接收 4 封邮件并验证数据完整性
    for (mrtk_u32_t i = 0; i < 4; ++i) {
        mrtk_u32_t recv_mail;
        mrtk_err_t ret = mrtk_mb_recv(&test_mb_static, &recv_mail, 0);
        EXPECT_EQ(ret, MRTK_EOK);
        EXPECT_EQ(recv_mail, (0xAABBCC00 | i));
    }

    EXPECT_EQ(test_mb_static.cur_mail_cnt, 0);
    EXPECT_EQ(test_mb_static.out_offset, 0); /* 回绕到 0 */
}

